#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum Status {
    Uninitialized,
    Active,
    Paused,
}

#[derive(Debug, Clone, Copy)]
struct State {
    total_deposits: u64,
    total_borrows: u64,
    interest_rate: u64,
    status: Status,
}

/// Proptest strategy for generating arbitrary State values.
fn arb_state() -> impl Strategy<Value = State> {
    (
        0u64..=u64::MAX,
        0u64..=u64::MAX,
        0u64..=u64::MAX,
        prop_oneof![Just(Status::Uninitialized), Just(Status::Active), Just(Status::Paused)],
    ).prop_map(|(total_deposits, total_borrows, interest_rate, status)| State {
        total_deposits,
        total_borrows,
        interest_rate,
        status,
    })
}

/// Boundary-biased strategy for guard rejection tests.
fn arb_boundary_state() -> impl Strategy<Value = State> {
    (
        prop_oneof![0u64..=3u64, (u64::MAX - 3)..=u64::MAX],
        prop_oneof![0u64..=3u64, (u64::MAX - 3)..=u64::MAX],
        prop_oneof![0u64..=3u64, (u64::MAX - 3)..=u64::MAX],
        prop_oneof![Just(Status::Uninitialized), Just(Status::Active), Just(Status::Paused)],
    ).prop_map(|(total_deposits, total_borrows, interest_rate, status)| State {
        total_deposits,
        total_borrows,
        interest_rate,
        status,
    })
}

/// pool_solvency: s.total_deposits ≥ s.total_borrows
fn pool_solvency(s: &State) -> bool {
    s.total_deposits >= s.total_borrows
}

fn init_pool(s: &mut State, rate: u64) -> bool {
    if !(rate > 0) {
        return false;
    }
    if s.status != Status::Uninitialized {
        return false;
    }
    s.interest_rate = rate;
    s.total_deposits = 0;
    s.total_borrows = 0;
    s.status = Status::Active;
    true
}

fn deposit(s: &mut State, amount: u64) -> bool {
    if !(amount > 0) {
        return false;
    }
    if s.status != Status::Active {
        return false;
    }
    s.total_deposits = s.total_deposits.wrapping_add(amount);
    s.status = Status::Active;
    true
}

